   184	// detectProviderOrHarness looks up a name against providers first, then
   185	// harnesses, returning the resolved kind and quota signal (if any).
   186	func detectProviderOrHarness(ctx context.Context, r *queryResolver, name string) (ProviderKind, *detectedRow) {
   187		if svc, err := agentlib.New(agentlib.ServiceOptions{}); err == nil {
   188			harnesses, _ := svc.ListHarnesses(ctx)
   189			for _, h := range harnesses {
   190				if strings.EqualFold(h.Name, name) {
   191					q := quotaFromHarnessInfo(h)
   192					return ProviderKindHarness, detectedFromQuota(q)
   193				}
   194			}
   195		}
   196		if snapshots, ok, _ := agent.ConfiguredProviderSnapshots(r.workingDir(ctx)); ok {
   197			for _, p := range snapshots {
   198				if strings.EqualFold(p.Name, name) {
   199					q := quotaFromProviderInfo(p)
   200					return ProviderKindEndpoint, detectedFromQuota(q)
   201				}
   202			}
   203		}
   204		if providers, err := liveProviderInfos(ctx, r.workingDir(ctx)); err == nil {
   205			for _, p := range providers {
   206				if strings.EqualFold(p.Name, name) {
   207					q := quotaFromProviderInfo(p)
   208					return ProviderKindEndpoint, detectedFromQuota(q)
   209				}
   210			}
   211		}
   212		return ProviderKindEndpoint, nil
   213	}
   214	
   215	func detectedFromQuota(q *ProviderQuota) *detectedRow {
   216		if q == nil {
   217			return nil
   218		}
   219		row := &detectedRow{ceilingTokens: -1, remaining: -1}
   220		if q.CeilingTokens != nil {

---
   220		if q.CeilingTokens != nil {
   221			row.ceilingTokens = *q.CeilingTokens
   222		}
   223		if q.Remaining != nil {
   224			row.remaining = *q.Remaining
   225		}
   226		return row
   227	}
   228	
   229	// projectRunOutHours returns the hours projected until current headroom is used
   230	// based on the last-24-hour slope of the bucket series. Returns 0 when the
   231	// slope is non-positive, headroom is gone/unknown, or the series is too
   232	// short to estimate.
   233	func projectRunOutHours(buckets []agent.UsageBucket, remaining float64) float64 {
   234		if len(buckets) < 2 {
   235			return 0
   236		}
   237		// Last 24 hours of buckets; if series is bucketed in 4h blocks, that's 6
   238		// buckets; 1h buckets gives 24.
   239		n := 24
   240		if n > len(buckets) {
   241			n = len(buckets)
   242		}
   243		tail := buckets[len(buckets)-n:]
   244		tokens := make([]float64, len(tail))
   245		for i, b := range tail {
   246			tokens[i] = float64(b.Tokens)
   247		}
   248		perBucket := agent.LinearSlope(tokens)
   249		// Convert slope-per-bucket to slope-per-hour.
   250		var bucketHours float64
   251		if len(tail) >= 2 {
   252			bucketHours = tail[1].Start.Sub(tail[0].Start).Hours()
   253		}
   254		if bucketHours <= 0 {
   255			bucketHours = 1
   256		}
   257		perHour := perBucket / bucketHours
   258		if perHour <= 0 {
   259			return 0
   260		}
   261		if remaining <= 0 {
   262			return 0
   263		}
   264		hours := remaining / perHour
   265		if hours <= 0 {
   266			return 0
   267		}
   268		return hours
   269	}
   270	
   271	func sumTailTokens(buckets []agent.UsageBucket, maxBuckets int) int {
   272		if maxBuckets <= 0 || len(buckets) == 0 {
   273			return 0
   274		}
   275		if maxBuckets > len(buckets) {
   276			maxBuckets = len(buckets)
   277		}
   278		total := 0
   279		for _, b := range buckets[len(buckets)-maxBuckets:] {
   280			total += b.Tokens
   281		}
   282		return total
   283	}
