   331	func providerStatusesFromInfos(providers []agentlib.ProviderInfo, entries []agent.SessionIndexEntry, now time.Time) []*ProviderStatus {
   332		lastChecked := now.UTC().Format(time.RFC3339)
   333		results := make([]*ProviderStatus, 0, len(providers))
   334		for _, p := range providers {
   335			url := p.BaseURL
   336			if url == "" {
   337				url = "(api)"
   338			}
   339			ps := &ProviderStatus{
   340				Name:              p.Name,
   341				Kind:              ProviderKindEndpoint,
   342				ProviderType:      p.Type,
   343				BaseURL:           url,
   344				Model:             p.DefaultModel,
   345				Status:            p.Status,
   346				Reachable:         providerReachable(p),
   347				Detail:            providerDetail(p),
   348				ModelCount:        p.ModelCount,
   349				IsDefault:         p.IsDefault,
   350				LastCheckedAt:     strPtr(lastChecked),
   351				DefaultForProfile: defaultProfilesForEndpoint(p),
   352			}
   353			if ps.ProviderType == "" {
   354				ps.ProviderType = "endpoint"
   355			}
   356			if p.CooldownState != nil && !p.CooldownState.Until.IsZero() {
   357				s := p.CooldownState.Until.UTC().Format(time.RFC3339)
   358				ps.CooldownUntil = &s
   359			}
   360			ps.Usage = buildUsage(entries, p.Name, agent.MatchProvider, now)
   361			ps.RecentWorkerCount = recentWorkerCount(entries, p.Name, agent.MatchProvider, now)
   362			ps.Quota = quotaFromProviderInfo(p)
   363			ps.Sparkline = buildSparkline(entries, p.Name, agent.MatchProvider, now)
   364			results = append(results, ps)
   365		}
   366		return results
   367	}
