   396	func providerRowsWithUsage(rows []*ProviderStatus, entries []agent.SessionIndexEntry, now time.Time) []*ProviderStatus {
   397		out := cloneProviderRows(rows)
   398		for _, row := range out {
   399			row.Usage = buildUsage(entries, row.Name, agent.MatchProvider, now)
   400			row.RecentWorkerCount = recentWorkerCount(entries, row.Name, agent.MatchProvider, now)
   401			row.Sparkline = buildSparkline(entries, row.Name, agent.MatchProvider, now)
   402		}
