   589	// defaultProfilesForEndpoint returns the profile names where this endpoint is
   590	// a default candidate. Current service surface exposes only a single
   591	// IsDefault flag, so we return ["default"] when set, [] otherwise. The return
   592	// shape supports multi-profile expansion without breaking callers.
   593	func defaultProfilesForEndpoint(p agentlib.ProviderInfo) []string {
   594		if p.IsDefault {
   595			return []string{"default"}
   596		}
   597		return []string{}
   598	}
